options.dotDiagram:
digraph G {
  rankdir=LR;
  bgcolor="transparent";
  fontname="Inter";
  node [shape=box, style="rounded,filled", fontname="Inter", fontsize=12, margin="0.2,0.12", penwidth=2];
  edge [fontname="Inter", fontsize=10, color="#888", penwidth=1.5];

  subgraph cluster_src {
    label=<<b>📥 Sorgenti</b>>;
    style="filled,rounded"; color="#222"; fillcolor="#1c2030"; fontcolor="#ddd"; fontname="Inter";
    csv  [label="CSV\n(scripts/rawdata)", fillcolor="#fde68a", color="#a16207", fontcolor="#3f2a00"];
    odt  [label="ODT/ODS\n(odt-to-text)", fillcolor="#fde68a", color="#a16207", fontcolor="#3f2a00"];
    html [label="HTML\n(Cheerio)", fillcolor="#fde68a", color="#a16207", fontcolor="#3f2a00"];
    md   [label="MD/TXT", fillcolor="#fde68a", color="#a16207", fontcolor="#3f2a00"];
  }

  subgraph cluster_ingest {
    label=<<b>⚙ Ingestion</b><br/><font point-size="10">worker · ${worker_replicas} replica</font>>;
    style="filled,rounded"; color="#222"; fillcolor="#0f2235"; fontcolor="#cfe0ff"; fontname="Inter";
    loader   [label="loader\n+ tag-map", fillcolor="#bfdbfe", color="#1d4ed8", fontcolor="#0f172a"];
    splitter [label="splitter\nchunk=1000\noverlap=200", fillcolor="#bfdbfe", color="#1d4ed8", fontcolor="#0f172a"];
    embed    [label="OpenAI Embeddings\ntext-embedding-3-large", fillcolor="#bfdbfe", color="#1d4ed8", fontcolor="#0f172a"];
    batcher  [label="batcher\nbatchSize=300", fillcolor="#bfdbfe", color="#1d4ed8", fontcolor="#0f172a"];
    worker   [label="worker\n${worker_replicas} ready", fillcolor="#a7f3d0", color="#047857", fontcolor="#052e1f"];
  }

  subgraph cluster_storage {
    label=<<b>🗄 Storage</b>>;
    style="filled,rounded"; color="#222"; fillcolor="#0a2820"; fontcolor="#a7f3d0"; fontname="Inter";
    qdrant   [label="Qdrant\nvectors=${vectors_total}\ncols=${collections_n}\nrps=${qdrant_rps}\nlat=${qdrant_lat_ms}ms", fillcolor="#86efac", color="#15803d", fontcolor="#052e1f"];
    redis    [label="Redis\ncache", fillcolor="#fecaca", color="#b91c1c", fontcolor="#3f0a0a"];
    pg       [label="Postgres\nPayload CMS\n(metadata + auth)", fillcolor="#ddd6fe", color="#6d28d9", fontcolor="#1e1b4b"];
  }

  subgraph cluster_serve {
    label=<<b>🌐 Serving</b><br/><font point-size="10">webapp · ${webapp_replicas} replica</font>>;
    style="filled,rounded"; color="#222"; fillcolor="#3b1d0a"; fontcolor="#ffd9b3"; fontname="Inter";
    webapp [label="Next.js webapp\n${webapp_replicas} replica\n/api/chat", fillcolor="#fed7aa", color="#c2410c", fontcolor="#3b1d0a"];
    user   [label="User", shape=ellipse, fillcolor="#f5f5f5", color="#71717a"];
  }

  csv  -> loader [label="csv→text"];
  odt  -> loader [label="odt→text"];
  html -> loader [label="cheerio"];
  md   -> loader;
  loader   -> splitter [label="docs"];
  splitter -> embed    [label="splits"];
  embed    -> batcher  [label="vectors"];
  batcher  -> qdrant   [label="addDocuments"];

  user   -> webapp [label="chat"];
  webapp -> redis  [label="cache"];
  webapp -> pg     [label="payload"];
  webapp -> qdrant [label="similaritySearch"];
}
